import javax.xml.bind.JAXBException;
import javax.xml.bind.Unmarshaller;
import java.io.StringReader;

public class DataProcessingService {

    public UserProfile processUserProfile(String xmlData) {
        if (xmlData == null || xmlData.trim().isEmpty()) {
            throw new IllegalArgumentException("Input XML data cannot be null or empty");
        }

        try {
            // Create JAXB context for UserProfile
            JAXBContext jaxbContext = JAXBContext.newInstance(UserProfile.class);
            // Create unmarshaller instance
            Unmarshaller unmarshaller = jaxbContext.createUnmarshaller();
            // Unmarshal XML string to UserProfile object
            try (StringReader reader = new StringReader(xmlData)) {
                return (UserProfile) unmarshaller.unmarshal(reader);
            }
        } catch (JAXBException e) {
            throw new RuntimeException("Failed to parse XML data into UserProfile: " + e.getMessage(), e);
        }
    }
}

